body.script:
        window.onload = () => {
            var ecobarLocalConfig = {
                "app_id": "MSI174XUT18B8",
                "network": {
                    "trackAnalytics" : "false",
                    "classification": window.classification
                },
                "ui": {
                    "zIndex": "0",    
                    "hideClassificationWarning": "true",
                    "hideClassification": "false",
                    "hideFooter": "true",
                    "appendFooterToSelector": "#bottom",
                    "siteContentSelector": "#root"
                }
            };

            window.ecobarApp && ecobarApp.init(ecobarLocalConfig);
        };

      var _paq = _paq || [];
      pushData(window.location.href);
      document.addEventListener('click', callback);

      function callback(e) {
        var e = window.e || e;
        if (e.target.tagName !== 'A'){
          //not a link
          return;
        }
        pushData(event.target.href);
        return;
      }

      function pushData(href) {
        if(window.classification === "unclassified" || window.classification === "unclassified//limdis") {
          //don't track clicks that aren't a page navigation.
          if(href === ""){
            return;
          }
          /* tracker methods like "setCustomDimension" should be called before "trackPageView" */
          _paq.push(['setCustomUrl', href]);
          _paq.push(['setReferrerUrl', window.location.href]);
          
          //set user id for tracking specific users on nipr (and eventually SC/TC)
          var persist = window.localStorage.getItem("reduxPersist:userReducer");
          if(persist){
            var email = JSON.parse(persist).userEmail;
            _paq.push(['setUserId', email]);
          }
          _paq.push(['trackPageView']);
          _paq.push(['enableLinkTracking']);
          _paq.push(['setDocumentTitle', window.location.href]);

          (function() {
            //set url, siteId based on location          
            var u="//gasmetrics.nga.mil/piwik/";
            _paq.push(['setTrackerUrl', u+'piwik.php']);
            _paq.push(['setSiteId', '297']);

            var secondaryTracker = "//matomo.east.paas.nga.mil/piwik.php"
            var secondarySiteId = null;
            if(window.location.hostname === "msi.nga.mil" || window.location.hostname === "msi.gs.mil"){
              secondarySiteId = 24;
              _paq.push(["setCookieDomain", "*.msi.nga.mil"]);
              _paq.push(['addTracker', secondaryTracker, secondarySiteId]);
            } else if (window.location.hostname === "msi.geo.nga.mil"){
              secondarySiteId = 45
              _paq.push(["setCookieDomain", "*.msi.geo.nga.mil"]);
              _paq.push(['addTracker', secondaryTracker, secondarySiteId]);
            }

            var d=document, g=d.createElement('script'), s=d.getElementsByTagName('script')[0];
            g.type='text/javascript'; g.async=true; g.defer=true; g.src=u+'piwik.js'; s.parentNode.insertBefore(g,s);
          })();
        }
      };
